const STORAGE_KEYS = {
  ADS: 'ecobr232_ads',
  ALERTS: 'ecobr232_alerts',
  USER_STATS: 'ecobr232_referral_stats'
};

const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

export const db = {
  ads: {
    async getAll(): Promise<StoredAd[]> {
      const data = localStorage.getItem(STORAGE_KEYS.ADS);
      return data ? JSON.parse(data) : [];
    },
    async save(ad: Omit<StoredAd, 'id' | 'createdAt' | 'rating' | 'isVerified'>): Promise<StoredAd> {
      await delay(300);
      const ads = await this.getAll();
      const newAd: StoredAd = {
        ...ad,
        id: Math.random().toString(36).substr(2, 9),
        createdAt: Date.now(),
        rating: 5.0,
        isVerified: false
      };
      localStorage.setItem(STORAGE_KEYS.ADS, JSON.stringify([newAd, ...ads]));
      return newAd;
    },
    async delete(id: string): Promise<void> {
      const ads = await this.getAll();
      const filtered = ads.filter(a => a.id !== id);
      localStorage.setItem(STORAGE_KEYS.ADS, JSON.stringify(filtered));
    }
  },
  alerts: {
    async getAll(): Promise<StoredAlert[]> {
      const data = localStorage.getItem(STORAGE_KEYS.ALERTS);
      return data ? JSON.parse(data) : [];
    },
    async save(alert: Omit<StoredAlert, 'id' | 'timestamp'>): Promise<StoredAlert> {
      await delay(300);
      const alerts = await this.getAll();
      const newAlert: StoredAlert = {
        ...alert,
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now()
      };
      localStorage.setItem(STORAGE_KEYS.ALERTS, JSON.stringify([newAlert, ...alerts]));
      return newAlert;
    }
  },
  referrals: {
    async getStats(): Promise<ReferralStats> {
      const data = localStorage.getItem(STORAGE_KEYS.USER_STATS);
      if (data) return JSON.parse(data);

      const defaultStats: ReferralStats = {
        referralCode: 'ADM-232',
        totalReferrals: 0,
        pendingCredits: 0,
        adCredits: 0,
        commissionRate: 0.10,
        campaignStart: Date.now(),
        campaignDurationDays: 30,
        benefitExpiryMonths: 24
      };
      localStorage.setItem(STORAGE_KEYS.USER_STATS, JSON.stringify(defaultStats));
      return defaultStats;
    },
    // Helper para simular avanço no tempo da campanha
    async simulateTimeProgress(days: number): Promise<void> {
      const stats = await this.getStats();
      const newStart = stats.campaignStart - (days * 24 * 60 * 60 * 1000);
      localStorage.setItem(STORAGE_KEYS.USER_STATS, JSON.stringify({
        ...stats,
        campaignStart: newStart
      }));
    }
  },
  system: {
    async resetAll(): Promise<void> {
      localStorage.clear();
    }
  }
};
